content.onCreate:
set("preset/reload", 1);
var hb_id = Math.floor(Math.random() * 1000000000);
setVar("root", "hb_id", hb_id);
send("/heartbeat", hb_id);
setInterval(function() {
    send("/heartbeat", getVar("root", "hb_id"))
}, 2000);
setInterval(function() {
    var v = get("root");
    if (v == 8) { send("/visualizer/enable_fft_spectrum", 1); send("/visualizer/enable_fft_gen_timeseries", 1); }
    if (v == 5) send("/visualizer/enable_synth", 1);
    if (v == 9) send("/visualizer/enable_fixture", 1);
}, 1000);

widgets.onValue:
locals.y_vals = []
for (var i = 0; i < get(id).length; i += 2) {
  locals.y_vals.push([get(id)[i], get(id)[i+1]])
}
set("fft_filter", locals.y_vals)

